{
  "name": "hello-rainbow-ui-req",
  "version": "0.1.0",
  "private": true,
  "description": "A small project demonstrating a Hello World rainbow UI with a tiny TypeScript dev server",
  "scripts": {
    "test": "jest",
    "build": "tsc",
    "start": "node dist/server.js",
    "dev": "ts-node src/server.ts",
    "serve": "npm run build && npm start"
  },
  "dependencies": {
    "express": "^4.18.2"
  },
  "devDependencies": {
    "@types/express": "^4.17.17",
    "@types/jest": "^29.5.3",
    "@types/node": "^20.5.1",
    "jest": "^29.6.0",
    "ts-jest": "^29.1.0",
    "ts-node": "^10.9.1",
    "typescript": "^5.2.2"
  }
}

import express from 'express';
import path from 'path';

const app = express();
const port = process.env.PORT ? Number(process.env.PORT) : 3000;

// Serve static files from the public directory (projectRoot/public)
app.use(express.static(path.join(__dirname, '..', 'public')));

// Fallback route to index.html for the root
app.get('/', (req, res) => {
  res.sendFile(path.join(__dirname, '..', 'public', 'index.html'));
});

app.listen(port, () => {
  console.log(`Hello Rainbow UI dev server running at http://localhost:${port}`);
});

/* Rainbow gradient text with subtle animation */
html,body{
  height:100%;
  margin:0;
  font-family:system-ui, -apple-system, 'Segoe UI', Roboto, 'Helvetica Neue', Arial;
  background: linear-gradient(180deg, #0f172a 0%, #071133 100%);
  color: #ffffff;
}

main{
  height:100%;
  display:flex;
  flex-direction:column;
  justify-content:center;
  align-items:center;
  text-align:center;
  padding:2rem;
}

h1#greeting{
  font-size:clamp(2.5rem, 8vw, 6rem);
  line-height:1;
  margin:0;
  background: linear-gradient(90deg, #ff004c 0%, #ff8a00 16%, #ffec00 33%, #00d084 50%, #0078ff 66%, #6b00ff 83%, #ff2dff 100%);
  -webkit-background-clip: text;
  background-clip: text;
  color: transparent;
  /* animate background position to create a moving rainbow feel */
  background-size: 200% 200%;
  animation: rainbowShift 6s linear infinite;
  cursor: pointer;
  outline: none;
}

.hint{
  margin-top:1rem;
  opacity:0.8;
  font-size:0.95rem;
}

@keyframes rainbowShift{
  0%{background-position:0% 50%;}
  50%{background-position:100% 50%;}
  100%{background-position:0% 50%;}
}

/* Focus styles for accessibility */
#greeting:focus{
  box-shadow: 0 0 0 4px rgba(255,255,255,0.08);
  border-radius:8px;
}

(function(){
  // Lightweight client script — add a small interaction and keyboard support
  const el = document.getElementById('greeting');
  if (!el) return;

  function announce() {
    // simple action — for demonstration only
    try {
      // Use the Web Speech API if available for a short friendly greeting
      if ('speechSynthesis' in window) {
        const msg = new SpeechSynthesisUtterance('Hello World');
        window.speechSynthesis.cancel();
        window.speechSynthesis.speak(msg);
      } else {
        console.log('Hello World');
      }
    } catch (e) {
      console.log('Hello World');
    }
  }

  el.setAttribute('tabindex', '0');
  el.setAttribute('role', 'heading');

  el.addEventListener('click', announce);
  el.addEventListener('keydown', function (ev) {
    if (ev.key === 'Enter' || ev.key === ' ') {
      ev.preventDefault();
      announce();
    }
  });
})();

import fs from 'fs';
import path from 'path';

describe('mockup files', () => {
  test('public/index.html contains Hello World and references assets', () => {
    const htmlPath = path.join(__dirname, '..', 'public', 'index.html');
    const html = fs.readFileSync(htmlPath, 'utf8');
    expect(html).toMatch(/Hello World/);
    expect(html).toMatch(/styles\.css/);
    expect(html).toMatch(/main\.js/);
  });

  test('styles.css contains rainbow animation', () => {
    const cssPath = path.join(__dirname, '..', 'public', 'styles.css');
    const css = fs.readFileSync(cssPath, 'utf8');
    expect(css).toMatch(/@keyframes rainbowShift/);
    expect(css).toMatch(/background: linear-gradient/);
  });
});
